const raw = $input.first().json;
const p = raw.body || raw;

const cliente = p.cliente || '';
const cidade = p.cidade || '';
const valor = Number(p.valorTotal) || 0;
const prod = Array.isArray(p.produtos) ? p.produtos.join(', ') : '';
const pid = p.id || 0;

let regra = 'Se valor > 2000: perfil Cliente Premium, cupom PREMIUM15 (15%)';
regra += ', se > 1000: Cliente Gold, cupom GOLD10 (10%)';
regra += ', se <= 1000: Cliente Essencial, cupom ESSENTIAL5 (5%)';

var prompt = 'Consultor de vendas loja de tecnologia. ';
prompt += 'Pedido: Cliente ' + cliente + ', cidade ' + cidade + ', valor R$ ' + valor + ', produtos: ' + prod + '. ';
prompt += regra + '. ';
prompt += 'Retorne SOMENTE este JSON com strings (nao arrays/objetos): ';
prompt += '{"perfilCliente":"texto classificacao",';
prompt += '"produtosRecomendados":"produto1, produto2, produto3",';
prompt += '"mensagemPersonalizada":"mensagem com cupom"}';

return [{ json: { prompt: prompt, pedidoId: pid } }];

const r = $input.first().json;

if (!r.choices || !r.choices.length || !r.choices[0].message) {
  throw new Error('Resposta IA vazia: ' + JSON.stringify(r).substring(0, 200));
}

var raw = r.choices[0].message.content || '';
if (!raw && r.choices[0].message.reasoning) {
  raw = r.choices[0].message.reasoning;
}

raw = raw.replace(/```json/g, '').replace(/```/g, '').trim();

var response;
try {
  response = JSON.parse(raw);
} catch (e) {
  var m = raw.match(/\{[\s\S]*\}/);
  if (m) { response = JSON.parse(m[0]); }
  else { throw new Error('Nao conseguiu parsear JSON: ' + raw.substring(0, 200)); }
}

var pid = $('Montar Prompt').first().json.pedidoId;

var perfil = response.perfilCliente || 'Cliente Essencial';
if (typeof perfil === 'object') {
  perfil = 'Cliente ' + (perfil.nome || 'Essencial') + ' de ' + (perfil.cidade || '');
}

var rec = response.produtosRecomendados || 'Acessorios de tecnologia';
if (Array.isArray(rec)) { rec = rec.join(', '); }

var msg = response.mensagemPersonalizada || 'Obrigado pela compra!';
var cupomMatch = msg.match(/cupom[:\s]+(\w+)/i);
var cupom = cupomMatch ? cupomMatch[1] : 'PROMO10';

return [{
  json: {
    id: pid,
    perfilCliente: String(perfil),
    recomendacoes: String(rec),
    cupomDesconto: cupom,
    mensagemIA: String(msg)
  }
}];
